 10→/// Decision result from a gate check.
 11→#[derive(Debug, Clone, Copy, PartialEq)]
 12→pub enum GateDecision {
 13→    /// Phase/iteration is approved to proceed
 14→    Approved,
 15→    /// User chose "yes to all" - auto-approve remaining phases
 16→    ApprovedAll,
 17→    /// Phase/iteration was rejected (skip)
 18→    Rejected,
 19→    /// User wants to abort the orchestrator entirely
 20→    Aborted,
 21→}
 22→
 23→/// Decision result from an iteration gate check (for strict mode).
 24→#[derive(Debug, Clone, Copy, PartialEq)]
 25→pub enum IterationDecision {
 26→    /// Continue with this iteration
 27→    Continue,
 28→    /// Skip this iteration but continue the phase
 29→    Skip,
 30→    /// Stop the phase (don't run more iterations)
 31→    StopPhase,
 32→    /// Abort the entire orchestrator
 33→    Abort,
 34→}
 35→
 36→/// Tracks progress for autonomous mode decision-making.
 37→#[derive(Debug, Clone, Default)]
 38→pub struct ProgressTracker {
 39→    /// Number of consecutive iterations without file changes
 40→    pub stale_iterations: u32,
 41→    /// Last known file change count
 42→    pub last_file_count: usize,
 43→    /// Whether we've seen any progress signal
 44→    pub has_progress_signal: bool,
 45→    /// Last progress percentage (if any)
 46→    pub last_progress_pct: Option<u8>,
 47→}
 48→
 49→impl ProgressTracker {
 50→    pub fn new() -> Self {
 51→        Self::default()
 52→    }
 53→
 54→    /// Update tracker with latest changes and return whether progress was made.
 55→    pub fn update(&mut self, changes: &FileChangeSummary, progress_pct: Option<u8>) -> bool {
 56→        let current_count = changes.total_files();
 57→        let made_progress =
 58→            current_count > self.last_file_count || progress_pct > self.last_progress_pct;
 59→
 60→        if made_progress {
 61→            self.stale_iterations = 0;
 62→        } else {
 63→            self.stale_iterations += 1;
 64→        }
 65→
 66→        self.last_file_count = current_count;
 67→        if let Some(pct) = progress_pct {
 68→            self.has_progress_signal = true;
 69→            self.last_progress_pct = Some(pct);
 70→        }
 71→
 72→        made_progress
 73→    }
 74→
 75→    /// Check if we should auto-approve based on progress.
 76→    /// Returns true if making progress, false if stale.
 77→    pub fn is_making_progress(&self, stale_threshold: u32) -> bool {
 78→        self.stale_iterations < stale_threshold
 79→    }
 80→}
 81→
 82→/// Approval gate that controls phase and iteration execution based on permission mode.
 83→pub struct ApprovalGate {
 84→    /// Number of file changes below which to auto-approve (for Standard mode)
 85→    pub auto_threshold: usize,
 86→    /// Whether to skip all prompts (--yes flag)
 87→    pub skip_all: bool,
 88→    /// Number of stale iterations before requiring approval in autonomous mode
 89→    pub stale_threshold: u32,
 90→}
 91→
 92→impl ApprovalGate {
 93→    pub fn new(auto_threshold: usize, skip_all: bool) -> Self {
 94→        Self {
 95→            auto_threshold,
 96→            skip_all,
 97→            stale_threshold: 3, // Default: 3 stale iterations before prompting
 98→        }
 99→    }
100→
101→    /// Set the stale threshold for autonomous mode.
102→    pub fn with_stale_threshold(mut self, threshold: u32) -> Self {
103→        self.stale_threshold = threshold;
104→        self
105→    }
106→
107→    /// Check whether a phase should proceed (called at phase start).
108→    /// This is the main entry point for phase-level approval.
109→    pub fn check_phase(
110→        &mut self,
111→        phase: &Phase,
112→        previous_changes: Option<&FileChangeSummary>,
113→        ui: &OrchestratorUI,
114→    ) -> Result<GateDecision> {
115→        // Display phase header
116→        ui.print_phase_header(&phase.number, &phase.name, &phase.promise, phase.budget);
117→
118→        // Show previous changes if any
119→        if let Some(changes) = previous_changes {
120→            ui.print_previous_changes(changes);
121→        }
122→
123→        // Show permission mode if not standard
124→        if phase.permission_mode != PermissionMode::Standard {
125→            println!(
126→                "  {} {}",
127→                console::style("Mode:").dim(),
128→                console::style(phase.permission_mode.to_string()).cyan()
129→            );
130→        }
131→
132→        // ── Shortcut: --yes flag bypasses all gate logic ─────────────────────
133→        // When the operator passed --yes on the CLI, skip_all is true.
134→        // Every phase is unconditionally approved; no prompts are shown.
135→        if self.skip_all {
136→            println!("  {} (--yes flag)", console::style("Auto-approved").dim());
137→            return Ok(GateDecision::Approved);
138→        }
139→
140→        // ── Permission-mode dispatch ──────────────────────────────────────────
141→        // Each permission mode has a different approval strategy:
142→        //   Autonomous — always auto-approve; stale checks happen per-iteration.
143→        //   Readonly   — auto-approve start; write-blocking happens after each iter.
144→        //   Standard / Strict — threshold-based auto-approve when previous phase
145→        //                changed few files; otherwise prompt the operator.
146→        match phase.permission_mode {
147→            PermissionMode::Autonomous => {
148→                // Autonomous mode: auto-approve phase start
149→                println!(
150→                    "  {} (autonomous mode)",
151→                    console::style("Auto-approved").dim()
152→                );
153→                Ok(GateDecision::Approved)
154→            }
155→            PermissionMode::Readonly => {
156→                // Readonly mode: auto-approve (modifications will be blocked later)
157→                println!(
