233→    /// Validate file changes in readonly mode.
234→    /// Returns an error if modifications were detected that should be blocked.
235→    pub fn validate_readonly_changes(
236→        &self,
237→        phase: &Phase,
238→        changes: &FileChangeSummary,
239→    ) -> Result<()> {
240→        if !self.should_block_modifications(phase) {
241→            return Ok(());
242→        }
243→
244→        let total_modifications = changes.files_added.len() + changes.files_modified.len();
245→        if total_modifications > 0 {
246→            anyhow::bail!(
247→                "Readonly mode violation: {} file(s) were modified/added in readonly phase '{}'. \
248→                 Modified: {:?}, Added: {:?}",
249→                total_modifications,
250→                phase.name,
251→                changes.files_modified,
252→                changes.files_added
253→            );
254→        }
255→
256→        Ok(())
257→    }
