448→/// Default pivot prompt injected when autonomous mode detects stale progress.
449→const DEFAULT_PIVOT_PROMPT: &str = "CRITICAL: You have made no progress for multiple iterations. \
450→Your current approach is not working. Stop what you are doing. Analyze what went wrong, identify \
451→the root blocker, and try a fundamentally different strategy. Do not repeat previous attempts.";
452→
453→/// Tracks stale detection state for autonomous pivot behavior.
454→#[derive(Debug, Clone, Default)]
455→pub struct StaleHandler {
456→    /// Whether a pivot prompt has already been issued.
457→    pub pivot_issued: bool,
458→}
459→
460→/// Autonomous gate strategy — no interactive prompts.
461→///
462→/// Auto-approves all phases and iterations. On stale progress:
463→/// 1. First stale: injects pivot prompt, resets stale counter, continues.
464→/// 2. Second stale: stops the phase.
465→pub struct AutonomousGateStrategy {
466→    /// Stale iteration threshold before action.
467→    pub stale_threshold: u32,
468→    /// Custom pivot prompt (overrides default).
469→    pub custom_pivot_prompt: Option<String>,
470→    /// Stale handler state.
471→    pub stale_handler: StaleHandler,
472→}
473→
474→impl AutonomousGateStrategy {
475→    pub fn new(stale_threshold: u32, custom_pivot_prompt: Option<String>) -> Self {
476→        Self {
477→            stale_threshold,
478→            custom_pivot_prompt,
479→            stale_handler: StaleHandler::default(),
480→        }
481→    }
482→
483→    /// Get the pivot prompt text.
484→    pub fn pivot_prompt(&self) -> &str {
485→        self.custom_pivot_prompt
486→            .as_deref()
487→            .unwrap_or(DEFAULT_PIVOT_PROMPT)
488→    }
489→
490→    /// Check a phase — always approves.
491→    pub fn check_phase(
492→        &self,
493→        _phase: &Phase,
494→        _previous_changes: Option<&FileChangeSummary>,
495→    ) -> GateDecision {
496→        GateDecision::Approved
497→    }
498→
499→    /// Check an iteration — always continues.
500→    pub fn check_iteration(
501→        &self,
502→        _phase: &Phase,
503→        _iteration: u32,
504→        _changes: Option<&FileChangeSummary>,
505→    ) -> IterationDecision {
506→        IterationDecision::Continue
507→    }
508→
509→    /// Check stale progress — pivot once, then stop.
510→    ///
511→    /// Returns `Continue` with pivot prompt on first stale detection.
512→    /// Returns `StopPhase` on second stale detection.
513→    /// The caller is responsible for injecting the pivot prompt when `Continue` is returned
514→    /// and `stale_handler.pivot_issued` transitions from false to true.
515→    pub fn check_stale_progress(
516→        &mut self,
517→        _phase: &Phase,
518→        tracker: &mut ProgressTracker,
519→    ) -> IterationDecision {
520→        if !tracker.is_making_progress(self.stale_threshold) {
521→            if self.stale_handler.pivot_issued {
522→                // Second stale detection — terminate
523→                return IterationDecision::StopPhase;
524→            }
525→            // First stale detection — pivot
526→            self.stale_handler.pivot_issued = true;
527→            tracker.stale_iterations = 0;
528→            return IterationDecision::Continue;
529→        }
530→        IterationDecision::Continue
531→    }
532→
533→    /// Check sub-phase spawn — auto-approve if within budget.
534→    pub fn check_sub_phase_spawn(
535→        &self,
536→        spawn_signal: &SubPhaseSpawnSignal,
537→        remaining_budget: u32,
538→    ) -> SubPhaseSpawnDecision {
539→        if spawn_signal.budget <= remaining_budget {
540→            SubPhaseSpawnDecision::Approved
541→        } else {
542→            debug!(
543→                "Sub-phase '{}' rejected: budget {} exceeds remaining {}",
544→                spawn_signal.name, spawn_signal.budget, remaining_budget
545→            );
546→            SubPhaseSpawnDecision::Skipped
547→        }
548→    }
549→
550→    /// Check sub-phase execution — always approves.
551→    pub fn check_sub_phase(&self, _sub_phase: &SubPhase, _parent: &Phase) -> GateDecision {
552→        GateDecision::Approved
553→    }
554→}
