105→impl PhaseAudit {
106→    pub fn new(phase_number: &str, description: &str, promise: &str) -> Self {
107→        Self {
108→            phase_number: phase_number.to_string(),
109→            description: description.to_string(),
110→            promise: promise.to_string(),
111→            started_at: Utc::now(),
112→            ended_at: None,
113→            iterations: Vec::new(),
114→            outcome: PhaseOutcome::InProgress,
115→            file_changes: FileChangeSummary::default(),
116→            compaction_events: Vec::new(),
117→            parent_phase: None,
118→            sub_phase_audits: Vec::new(),
119→        }
120→    }
121→
122→    /// Create a new PhaseAudit for a sub-phase with parent reference.
123→    pub fn new_sub_phase(
124→        phase_number: &str,
125→        parent_phase: &str,
126→        description: &str,
127→        promise: &str,
128→    ) -> Self {
129→        Self {
130→            phase_number: phase_number.to_string(),
131→            description: description.to_string(),
132→            promise: promise.to_string(),
133→            started_at: Utc::now(),
134→            ended_at: None,
135→            iterations: Vec::new(),
136→            outcome: PhaseOutcome::InProgress,
137→            file_changes: FileChangeSummary::default(),
138→            compaction_events: Vec::new(),
139→            parent_phase: Some(parent_phase.to_string()),
140→            sub_phase_audits: Vec::new(),
141→        }
142→    }
143→
144→    pub fn finish(&mut self, outcome: PhaseOutcome, changes: FileChangeSummary) {
145→        self.ended_at = Some(Utc::now());
146→        self.outcome = outcome;
147→        self.file_changes = changes;
148→    }
149→
150→    /// Record a compaction event.
151→    pub fn add_compaction_event(
152→        &mut self,
153→        iterations_compacted: u32,
154→        original_chars: usize,
155→        summary_chars: usize,
156→    ) {
157→        let compression_ratio = if original_chars > 0 {
158→            1.0 - (summary_chars as f32 / original_chars as f32)
159→        } else {
160→            0.0
161→        };
162→
163→        self.compaction_events.push(CompactionEvent {
164→            timestamp: Utc::now(),
165→            iterations_compacted,
166→            original_chars,
167→            summary_chars,
168→            compression_ratio,
169→        });
170→    }
171→
172→    /// Add an iteration audit entry to this phase.
173→    pub fn add_iteration(&mut self, iteration: IterationAudit) {
174→        self.iterations.push(iteration);
175→    }
176→
177→    /// Check if this is a sub-phase audit.
178→    pub fn is_sub_phase(&self) -> bool {
179→        self.parent_phase.is_some()
180→    }
181→
182→    /// Check if this phase has any sub-phase audits.
183→    pub fn has_sub_phases(&self) -> bool {
184→        !self.sub_phase_audits.is_empty()
185→    }
186→
187→    /// Add a sub-phase audit to this phase.
188→    pub fn add_sub_phase_audit(&mut self, sub_audit: SubPhaseAudit) {
189→        self.sub_phase_audits.push(sub_audit);
190→    }
191→
192→    /// Get a sub-phase audit by number.
193→    pub fn get_sub_phase_audit(&self, number: &str) -> Option<&SubPhaseAudit> {
194→        self.sub_phase_audits
195→            .iter()
196→            .find(|spa| spa.sub_phase_number == number)
197→    }
198→
199→    /// Get a mutable sub-phase audit by number.
200→    pub fn get_sub_phase_audit_mut(&mut self, number: &str) -> Option<&mut SubPhaseAudit> {
201→        self.sub_phase_audits
202→            .iter_mut()
203→            .find(|spa| spa.sub_phase_number == number)
204→    }
205→
206→    /// Count total iterations including sub-phase iterations.
207→    pub fn total_iterations(&self) -> usize {
208→        self.iterations.len()
209→            + self
210→                .sub_phase_audits
211→                .iter()
212→                .map(|spa| spa.iterations.len())
213→                .sum::<usize>()
214→    }
215→
216→    /// Get aggregate file changes including sub-phases.
217→    pub fn total_file_changes(&self) -> FileChangeSummary {
218→        let mut summary = self.file_changes.clone();
219→        for spa in &self.sub_phase_audits {
220→            summary
221→                .files_added
222→                .extend(spa.file_changes.files_added.clone());
223→            summary
224→                .files_modified
225→                .extend(spa.file_changes.files_modified.clone());
226→            summary
227→                .files_deleted
228→                .extend(spa.file_changes.files_deleted.clone());
229→            summary.total_lines_added += spa.file_changes.total_lines_added;
230→            summary.total_lines_removed += spa.file_changes.total_lines_removed;
231→        }
232→        summary
233→    }
234→
235→    /// Check if all sub-phases completed successfully.
236→    pub fn all_sub_phases_completed(&self) -> bool {
237→        self.sub_phase_audits.is_empty()
238→            || self
239→                .sub_phase_audits
240→                .iter()
241→                .all(|spa| matches!(spa.outcome, PhaseOutcome::Completed { .. }))
242→    }
243→}
