255→            sub_phase_number: sub_phase_number.to_string(),
256→            parent_phase: parent_phase.to_string(),
257→            description: description.to_string(),
258→            promise: promise.to_string(),
259→            started_at: Utc::now(),
260→            ended_at: None,
261→            iterations: Vec::new(),
262→            outcome: PhaseOutcome::InProgress,
263→            file_changes: FileChangeSummary::default(),
264→            budget,
265→            iterations_used: 0,
266→        }
267→    }
268→
269→    /// Finish the sub-phase audit with final outcome.
270→    pub fn finish(&mut self, outcome: PhaseOutcome, changes: FileChangeSummary) {
271→        self.ended_at = Some(Utc::now());
272→        self.outcome = outcome;
273→        self.file_changes = changes;
274→        self.iterations_used = self.iterations.len() as u32;
275→    }
276→
277→    /// Add an iteration audit to this sub-phase.
278→    pub fn add_iteration(&mut self, iteration: IterationAudit) {
279→        self.iterations.push(iteration);
280→    }
281→
282→    /// Get duration in seconds.
283→    pub fn duration_secs(&self) -> Option<f64> {
284→        self.ended_at
285→            .map(|end| (end - self.started_at).num_milliseconds() as f64 / 1000.0)
286→    }
287→
288→    /// Check if this sub-phase completed successfully.
289→    pub fn is_successful(&self) -> bool {
290→        matches!(self.outcome, PhaseOutcome::Completed { .. })
291→    }
292→}
