  1→//! DAG scheduler for parallel phase execution.
  2→//!
  3→//! This module provides phase-level parallelism through a directed acyclic graph (DAG)
  4→//! scheduler. It builds a dependency graph from phases.json and executes phases in
  5→//! parallel waves while respecting dependencies.
  6→//!
  7→//! ## Architecture
  8→//!
  9→//! The DAG scheduler has three main components:
 10→//!
 11→//! 1. **Builder** - Constructs a DAG from phases with their dependencies
 12→//! 2. **Scheduler** - Computes execution waves and manages ready states
 13→//! 3. **Executor** - Runs phases in parallel with review integration
 14→//!
 15→//! ## Example
 16→//!
 17→//! ```no_run
 18→//! use forge::dag::{DagScheduler, DagConfig};
 19→//! use forge::phase::Phase;
 20→//!
 21→//! # async fn example() -> anyhow::Result<()> {
 22→//! let phases = vec![
 23→//!     Phase::new("01", "Setup", "SETUP DONE", 5, "Initial setup", vec![]),
 24→//!     Phase::new("02", "Core", "CORE DONE", 10, "Core work", vec!["01".to_string()]),
 25→//!     Phase::new("03", "Tests", "TESTS DONE", 8, "Testing", vec!["01".to_string()]),
 26→//!     Phase::new("04", "Docs", "DOCS DONE", 5, "Documentation", vec!["02".to_string(), "03".to_string()]),
 27→//! ];
 28→//!
 29→//! let config = DagConfig::default();
 30→//! let scheduler = DagScheduler::from_phases(&phases, config)?;
 31→//!
 32→//! // Compute execution waves
 33→//! let waves = scheduler.compute_waves();
 34→//! // Wave 0: [01] - no dependencies
 35→//! // Wave 1: [02, 03] - both depend only on 01
 36→//! // Wave 2: [04] - depends on 02 and 03
 37→//! # Ok(())
 38→//! # }
 39→//! ```
 40→
 41→mod builder;
 42→mod executor;
 43→mod scheduler;
 44→mod state;
 45→
 46→pub use builder::DagBuilder;
 47→pub use executor::{DagExecutor, ExecutionResult, ExecutorConfig, PhaseEvent};
 48→pub use scheduler::{
 49→    DagConfig, DagScheduler, PhaseNode, PhaseStatus, ReviewConfig, ReviewMode, SwarmBackend,
 50→};
 51→pub use state::{DagState, DagSummary, PhaseResult};
 52→
 53→#[cfg(test)]
 54→mod tests {
 55→    use super::*;
 56→    use crate::phase::Phase;
 57→
 58→    fn create_test_phases() -> Vec<Phase> {
 59→        vec![
 60→            Phase::new("01", "Setup", "SETUP DONE", 5, "Initial setup", vec![]),
 61→            Phase::new(
 62→                "02",
 63→                "Core A",
 64→                "CORE A DONE",
 65→                10,
 66→                "Core work A",
 67→                vec!["01".to_string()],
 68→            ),
 69→            Phase::new(
 70→                "03",
 71→                "Core B",
 72→                "CORE B DONE",
 73→                8,
 74→                "Core work B",
 75→                vec!["01".to_string()],
 76→            ),
 77→            Phase::new(
 78→                "04",
 79→                "Integration",
 80→                "INTEGRATION DONE",
 81→                5,
 82→                "Integration",
 83→                vec!["02".to_string(), "03".to_string()],
 84→            ),
 85→        ]
 86→    }
 87→
 88→    #[test]
 89→    fn test_dag_construction() {
 90→        let phases = create_test_phases();
 91→        let config = DagConfig::default();
 92→        let scheduler = DagScheduler::from_phases(&phases, config).unwrap();
 93→
 94→        assert_eq!(scheduler.phase_count(), 4);
 95→    }
 96→
 97→    #[test]
 98→    fn test_wave_computation() {
 99→        let phases = create_test_phases();
100→        let config = DagConfig::default();
101→        let scheduler = DagScheduler::from_phases(&phases, config).unwrap();
102→
103→        let waves = scheduler.compute_waves();
104→
105→        // Wave 0: Phase 01 (no dependencies)
106→        assert_eq!(waves.len(), 3);
