  1→//! Review system for quality gating in Forge.
  2→//!
  3→//! This module provides the review infrastructure that enables quality gates
  4→//! before phase progression. Review specialists examine phase outputs and
  5→//! provide verdicts that can optionally block further execution.
  6→//!
  7→//! ## Components
  8→//!
  9→//! - [`specialists`]: Review specialist types and configuration
 10→//! - [`findings`]: Review output types (findings, reports, aggregations)
 11→//! - [`arbiter`]: LLM-based resolution for failed reviews
 12→//!
 13→//! ## Example
 14→//!
 15→//! ```
 16→//! use forge::review::{ReviewSpecialist, SpecialistType};
 17→//! use forge::review::findings::{ReviewFinding, ReviewReport, ReviewVerdict, FindingSeverity};
 18→//!
 19→//! // Create a gating security review
 20→//! let security = ReviewSpecialist::gating(SpecialistType::SecuritySentinel);
 21→//!
 22→//! // Check focus areas
 23→//! let areas = security.focus_areas();
 24→//! assert!(areas.iter().any(|a| a.contains("injection")));
 25→//!
 26→//! // Create a review report with findings
 27→//! let finding = ReviewFinding::new(
 28→//!     FindingSeverity::Warning,
 29→//!     "src/auth.rs",
 30→//!     "Potential SQL injection"
 31→//! ).with_line(42);
 32→//!
 33→//! let report = ReviewReport::new("05", "security-sentinel", ReviewVerdict::Warn)
 34→//!     .with_summary("One finding related to SQL queries")
 35→//!     .add_finding(finding);
 36→//!
 37→//! // Create multiple specialists for comprehensive review
 38→//! let specialists = vec![
 39→//!     ReviewSpecialist::gating(SpecialistType::SecuritySentinel),
 40→//!     ReviewSpecialist::advisory(SpecialistType::PerformanceOracle),
 41→//!     ReviewSpecialist::advisory(SpecialistType::SimplicityReviewer),
 42→//! ];
 43→//! ```
 44→//!
 45→//! ## Arbiter Usage
 46→//!
 47→//! The arbiter handles failed reviews by deciding whether to proceed, fix, or escalate:
 48→//!
 49→//! ```
 50→//! use forge::review::{
 51→//!     ArbiterConfig, ArbiterInput, ArbiterVerdict,
 52→//!     ReviewAggregation, ReviewReport, ReviewVerdict, ReviewFinding, FindingSeverity,
 53→//! };
 54→//! use forge::review::arbiter::apply_rule_based_decision;
 55→//!
 56→//! // Create a failed review aggregation
 57→//! let finding = ReviewFinding::new(
 58→//!     FindingSeverity::Warning,
 59→//!     "src/auth.rs",
 60→//!     "Token stored in localStorage"
 61→//! );
 62→//! let report = ReviewReport::new("05", "security-sentinel", ReviewVerdict::Fail)
 63→//!     .add_finding(finding);
 64→//! let aggregation = ReviewAggregation::new("05").add_report(report);
 65→//!
 66→//! // Create arbiter input from the aggregation
 67→//! let input = ArbiterInput::from_aggregation(&aggregation, 20, 5)
 68→//!     .with_phase_name("OAuth Integration");
 69→//!
 70→//! // Configure arbiter (using rule-based for sync example)
 71→//! let config = ArbiterConfig::arbiter_mode()
 72→//!     .with_confidence_threshold(0.7);
 73→//!
 74→//! // Get a rule-based decision
 75→//! let decision = apply_rule_based_decision(&input, &config);
 76→//!
 77→//! match decision.decision {
 78→//!     ArbiterVerdict::Proceed => println!("Proceeding despite findings"),
 79→//!     ArbiterVerdict::Fix => println!("Attempting to fix: {:?}", decision.fix_instructions),
 80→//!     ArbiterVerdict::FailPhase => println!("Phase failed: {:?}", decision.failure_summary),
 81→//! }
 82→//! ```
