//! Dynamic Decomposition module for Forge.
//!
//! This module handles automatic detection and decomposition of complex phases
//! into smaller, manageable sub-tasks. It provides:
//!
//! - **Detection**: Identifies when a phase needs decomposition based on budget
//!   usage and complexity signals from Claude output
//! - **Parsing**: Extracts decomposition requests from Claude's XML output
//! - **Conversion**: Transforms decomposed tasks into SubPhase objects
//! - **Execution**: Coordinates sub-task execution with progress tracking
//!
//! ## Trigger Conditions
//!
//! Decomposition is triggered when:
//! 1. Worker emits `<blocker>` with complexity signal
//! 2. Iterations > threshold% of budget with progress < 30%
//! 3. Worker explicitly requests: `<request-decomposition/>`
//!
//! ## Example
//!
//! ```no_run
//! use forge::decomposition::{DecompositionDetector, DecompositionConfig};
//! use forge::phase::Phase;
//!
//! let config = DecompositionConfig::default();
//! let detector = DecompositionDetector::new(config);
//!
//! // Check if decomposition is needed
//! let phase = Phase::new("05", "OAuth Integration", "OAUTH DONE", 20, "Implement OAuth", vec![]);
//! let trigger = detector.check_trigger(&phase, 12, 20);
//!
//! if trigger.should_decompose() {
//!     println!("Decomposition reason: {}", trigger.description());
//! }
//! ```

mod config;
mod detector;
mod executor;
mod parser;
mod types;

pub use config::{DEFAULT_COMPLEXITY_KEYWORDS, DecompositionConfig, default_complexity_keywords};
pub use detector::{DecompositionDetector, DecompositionTrigger, ExecutionSignals, TriggerReason};
pub use executor::{DecompositionExecutor, ExecutionSummary};
pub use parser::{
    extract_decomposition_reason, parse_decomposition_output, parse_decomposition_request,
    validate_decomposition,
};
pub use types::{
    DecomposedPhase, DecompositionResult, DecompositionTask, IntegrationTask, TaskStatus,
};

//! Hook system for event-driven extensibility in Forge.
//!
//! The hook system allows users to intercept and modify behavior at key points
//! in the orchestration lifecycle. Hooks can be used to:
//! - Run setup/teardown scripts before/after phases
//! - Validate conditions before proceeding
//! - Inject additional context into prompts
//! - Auto-approve based on custom logic
//!
//! # Hook Events
//!
//! - `PrePhase` - Before phase execution
//! - `PostPhase` - After phase completion
//! - `PreIteration` - Before each Claude invocation
//! - `PostIteration` - After each Claude response
//! - `OnFailure` - When phase exceeds budget without promise
//! - `OnApproval` - When approval gate is presented
//!
//! # Hook Types
//!
//! - **Command hooks**: Execute a bash script that receives JSON context via stdin.
//!   Exit codes control flow: 0=Continue, 1=Block, 2=Skip, 3=Approve, 4=Reject.
//!   Stdout can return JSON for structured results or plain text to inject.
//!
//! - **Prompt hooks**: (Phase 03) Use a small LLM to evaluate conditions.
//!
//! # Configuration
//!
//! Hooks are configured in `.forge/hooks.toml`:
//!
//! ```toml
//! [[hooks]]
//! event = "pre_phase"
//! match = "database-*"
//! command = "./scripts/ensure-db-running.sh"
//!
//! [[hooks]]
//! event = "post_iteration"
//! command = "./scripts/check-progress.sh"
//! timeout_secs = 60
//! ```
//!
//! Or in the `[hooks]` section of `.forge/forge.toml`.
//!
//! # Usage
//!
//! ```ignore
//! use forge::hooks::{HookManager, HookEvent};
//!
//! let manager = HookManager::new(&project_dir, verbose)?;
//!
//! // Run hooks for an event
//! let result = manager.run_pre_phase(&phase, previous_changes).await?;
//!
//! if !result.should_continue() {
//!     // Handle block/skip/reject
//! }
//!
//! if let Some(inject) = result.inject {
//!     // Add injected content to prompt
//! }
//! ```

pub mod config;
pub mod executor;
pub mod manager;
pub mod types;

// Re-exports for convenience
