 36→use std::collections::HashMap;
 37→use std::path::{Path, PathBuf};
 38→use tracing::warn;
 39→
 40→/// The name of the skills directory within .forge
 41→pub const SKILLS_DIR: &str = "skills";
 42→
 43→/// The filename for skill content
 44→pub const SKILL_FILE: &str = "SKILL.md";
 45→
 46→/// A loaded skill with its content and metadata.
 47→#[derive(Debug, Clone)]
 48→pub struct Skill {
 49→    /// The skill name (directory name)
 50→    pub name: String,
 51→    /// The full path to the skill directory
 52→    pub path: PathBuf,
 53→    /// The content of SKILL.md
 54→    pub content: String,
 55→}
 56→
 57→impl Skill {
 58→    /// Create a new Skill from a path and content.
