 60→        Self {
 61→            name: name.to_string(),
 62→            path,
 63→            content,
 64→        }
 65→    }
 66→
 67→    /// Get the skill content formatted for injection into a prompt.
 68→    pub fn as_prompt_section(&self) -> String {
 69→        format!(
 70→            "## SKILL: {}\n\n{}",
 71→            self.name.to_uppercase().replace('-', " "),
 72→            self.content.trim()
 73→        )
