 77→/// Skills loader that manages loading and caching of skills.
 78→#[derive(Debug)]
 79→pub struct SkillsLoader {
 80→    /// Path to the skills directory (.forge/skills)
 81→    skills_dir: PathBuf,
 82→    /// Cache of loaded skills
 83→    cache: HashMap<String, Skill>,
 84→    /// Whether verbose logging is enabled
 85→    verbose: bool,
 86→}
 87→
 88→impl SkillsLoader {
 89→    /// Create a new SkillsLoader for the given forge directory.
 90→    pub fn new(forge_dir: &Path, verbose: bool) -> Self {
 91→        Self {
 92→            skills_dir: forge_dir.join(SKILLS_DIR),
 93→            cache: HashMap::new(),
 94→            verbose,
 95→        }
 96→    }
 97→
 98→    /// Load a single skill by name.
 99→    ///
100→    /// Returns None if the skill doesn't exist (with a warning if verbose).
101→    /// Returns an error only for I/O failures on existing skills.
102→    pub fn load_skill(&mut self, name: &str) -> Result<Option<Skill>> {
103→        // Check cache first
104→        if let Some(skill) = self.cache.get(name) {
105→            return Ok(Some(skill.clone()));
106→        }
107→
108→        let skill_dir = self.skills_dir.join(name);
109→        let skill_file = skill_dir.join(SKILL_FILE);
110→
111→        if !skill_file.exists() {
112→            if self.verbose {
113→                warn!("Skill '{}' not found at {}", name, skill_file.display());
114→            }
115→            return Ok(None);
116→        }
117→
118→        let content = std::fs::read_to_string(&skill_file)
119→            .with_context(|| format!("Failed to read skill file: {}", skill_file.display()))?;
120→
121→        let skill = Skill::new(name, skill_dir, content);
122→        self.cache.insert(name.to_string(), skill.clone());
123→
124→        Ok(Some(skill))
125→    }
126→
127→    /// Load multiple skills by name.
128→    ///
129→    /// Returns all successfully loaded skills, skipping missing ones.
130→    pub fn load_skills(&mut self, names: &[String]) -> Result<Vec<Skill>> {
131→        let mut skills = Vec::new();
132→        for name in names {
133→            if let Some(skill) = self.load_skill(name)? {
134→                skills.push(skill);
135→            }
136→        }
137→        Ok(skills)
138→    }
139→
140→    /// Generate a prompt section from a list of skill names.
141→    ///
142→    /// This is the main entry point for integrating skills into prompts.
143→    /// Returns an empty string if no skills are found.
144→    pub fn generate_skills_section(&mut self, skill_names: &[String]) -> Result<String> {
145→        let skills = self.load_skills(skill_names)?;
146→
147→        if skills.is_empty() {
148→            return Ok(String::new());
149→        }
150→
151→        let sections: Vec<String> = skills.iter().map(|s| s.as_prompt_section()).collect();
152→
153→        Ok(format!(
154→            "## SKILLS AND CONVENTIONS\n\nThe following skills provide guidance for this phase:\n\n{}\n\n",
155→            sections.join("\n\n---\n\n")
156→        ))
157→    }
158→
159→    /// List all available skills in the skills directory.
160→    pub fn list_skills(&self) -> Result<Vec<String>> {
161→        if !self.skills_dir.exists() {
162→            return Ok(Vec::new());
163→        }
164→
165→        let mut skills = Vec::new();
166→        let entries = std::fs::read_dir(&self.skills_dir).with_context(|| {
167→            format!(
168→                "Failed to read skills directory: {}",
169→                self.skills_dir.display()
170→            )
171→        })?;
172→
173→        for entry in entries {
174→            let entry = entry?;
175→            let path = entry.path();
176→            if path.is_dir()
177→                && path.join(SKILL_FILE).exists()
178→                && let Some(name) = path.file_name().and_then(|n| n.to_str())
179→            {
180→                skills.push(name.to_string());
181→            }
182→        }
183→
184→        skills.sort();
185→        Ok(skills)
186→    }
187→
188→    /// Get the path where a new skill should be created.
189→    pub fn skill_path(&self, name: &str) -> PathBuf {
190→        self.skills_dir.join(name)
191→    }
192→
193→    /// Check if the skills directory exists.
194→    pub fn skills_dir_exists(&self) -> bool {
195→        self.skills_dir.exists()
196→    }
197→
198→    /// Get the skills directory path.
199→    pub fn skills_dir(&self) -> &Path {
200→        &self.skills_dir
201→    }
202→}
203→
204→/// Create the skills directory structure.
205→pub fn ensure_skills_directory(forge_dir: &Path) -> Result<PathBuf> {
206→    let skills_dir = forge_dir.join(SKILLS_DIR);
207→    std::fs::create_dir_all(&skills_dir).with_context(|| {
208→        format!(
209→            "Failed to create skills directory: {}",
210→            skills_dir.display()
211→        )
212→    })?;
213→    Ok(skills_dir)
214→}
215→
216→/// Create a new skill with the given name and content.
217→pub fn create_skill(forge_dir: &Path, name: &str, content: &str) -> Result<PathBuf> {
218→    let skills_dir = ensure_skills_directory(forge_dir)?;
219→    let skill_dir = skills_dir.join(name);
220→    std::fs::create_dir_all(&skill_dir)
221→        .with_context(|| format!("Failed to create skill directory: {}", skill_dir.display()))?;
222→
223→    let skill_file = skill_dir.join(SKILL_FILE);
224→    std::fs::write(&skill_file, content)
225→        .with_context(|| format!("Failed to write skill file: {}", skill_file.display()))?;
226→
227→    Ok(skill_dir)
228→}
229→
230→/// Delete a skill by name.
231→pub fn delete_skill(forge_dir: &Path, name: &str) -> Result<()> {
232→    let skill_dir = forge_dir.join(SKILLS_DIR).join(name);
233→    if skill_dir.exists() {
234→        std::fs::remove_dir_all(&skill_dir)
235→            .with_context(|| format!("Failed to delete skill: {}", skill_dir.display()))?;
236→    }
237→    Ok(())
238→}
