        let dir = tempdir().unwrap();
        let forge_dir = dir.path().join(".forge");
        std::fs::create_dir_all(forge_dir.join("skills")).unwrap();

        // Should not error on nonexistent skill
        let result = delete_skill(&forge_dir, "nonexistent");
        assert!(result.is_ok());
    }
