108→
109→    // Check budget
110→    let available = parent
111→        .remaining_budget()
112→        .saturating_sub(config.min_parent_budget_reserve);
113→    if signal.budget > available {
114→        return SpawnValidation::InsufficientBudget {
115→            requested: signal.budget,
116→            available,
