118→    }
119→
120→    // Check sub-phase count
121→    if parent.sub_phases.len() >= config.max_sub_phases {
122→        return SpawnValidation::TooManySubPhases {
123→            current: parent.sub_phases.len(),
124→            max: config.max_sub_phases,
125→        };
126→    }
